BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?owner ?depType ?dep ?depName WHERE {
  {
    <TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::03%2520Processes::Information%2520Flow::Requirements%2520Information%2520Flow::APS%2520Requirements%2520Flowdown> vocab:Element_owner ?owner .
  }
  UNION
  {
    <TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::03%2520Processes::Information%2520Flow::Requirements%2520Information%2520Flow::APS%2520Requirements%2520Flowdown> vocab:NamedElement_supplierDependency ?dep .
    ?dep rdf:type ?depType .
    OPTIONAL { ?dep vocab:NamedElement_name ?depName . }
  }
}
LIMIT 25

