BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?flow ?flowType ?flowName ?sourceName ?targetName ?source ?target WHERE {
  ?l2 vocab:NamedElement_name ?l2name .
  FILTER(CONTAINS(STR(?l2name), "L2%20APS%20Requirements%20Document"))
  ?l2 vocab:NamedElement__informationFlowOfInformationTarget ?flow .
  ?flow rdf:type ?flowType .
  OPTIONAL { ?flow vocab:NamedElement_name ?flowName . }
  OPTIONAL { 
    ?flow vocab:InformationFlow_informationSource ?source .
    ?source vocab:NamedElement_name ?sourceName .
  }
  OPTIONAL {
    ?flow vocab:InformationFlow_informationTarget ?target .
    ?target vocab:NamedElement_name ?targetName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?rel ?relType ?relName ?sourceName ?targetName WHERE {
  {
    ?rel vocab:DirectedRelationship_source ?source .
    ?rel vocab:DirectedRelationship_target ?target .
    ?source vocab:NamedElement_name ?sourceName .
    ?target vocab:NamedElement_name ?targetName .
    FILTER(
      (CONTAINS(STR(?sourceName), "L2%20APS%20Requirements%20Document") && CONTAINS(STR(?targetName), "APS%20Requirements%20Flowdown")) ||
      (CONTAINS(STR(?sourceName), "APS%20Requirements%20Flowdown") && CONTAINS(STR(?targetName), "L2%20APS%20Requirements%20Document"))
    )
    ?rel rdf:type ?relType .
    OPTIONAL { ?rel vocab:NamedElement_name ?relName . }
  }
}
LIMIT 25

