BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?rel ?relType ?sourceName ?targetName ?source ?target WHERE {
  ?rel rdf:type ?relType .
  FILTER(?relType IN (vocab:item%20flow, vocab:dependency, vocab:connector, vocab:association))
  {
    ?rel vocab:DirectedRelationship_source ?source .
    ?rel vocab:DirectedRelationship_target ?target .
