  UNION
  {
    ?rel vocab:Dependency_client ?source .
    ?rel vocab:Dependency_supplier ?target .
  }
  OPTIONAL { ?source vocab:NamedElement_name ?sourceName . }
  OPTIONAL { ?target vocab:NamedElement_name ?targetName . }
  FILTER(
    CONTAINS(STR(?sourceName), "APS%20Requirements%20Flowdown") ||
    CONTAINS(STR(?targetName), "APS%20Requirements%20Flowdown")
  )
}
LIMIT 25

