BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?flow ?source ?target ?sourceName ?targetName WHERE {
  ?modelOutput vocab:NamedElement_name "Model%20Output" .
  ?flow rdf:type vocab:item%20flow .
  {
    ?flow vocab:InformationFlow_informationSource ?modelOutput .
    ?flow vocab:InformationFlow_informationTarget ?target .
    BIND(?modelOutput AS ?source)
    OPTIONAL { ?target vocab:NamedElement_name ?targetName . }
    BIND("Model%20Output" AS ?sourceName)
  }
  UNION
  {
    ?flow vocab:InformationFlow_informationTarget ?modelOutput .
    ?flow vocab:InformationFlow_informationSource ?source .
    BIND(?modelOutput AS ?target)
    OPTIONAL { ?source vocab:NamedElement_name ?sourceName . }
    BIND("Model%20Output" AS ?targetName)
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?rel ?relType ?source ?target ?sourceName ?targetName WHERE {
  {
    ?rel rdf:type ?relType .
    ?rel vocab:DirectedRelationship_source ?source .
    ?rel vocab:DirectedRelationship_target ?target .
    FILTER(
      (CONTAINS(STR(?source), "L2%20APS%20Requirements%20Document") && CONTAINS(STR(?target), "APS%20Requirements%20Flowdown")) ||
      (CONTAINS(STR(?source), "APS%20Requirements%20Flowdown") && CONTAINS(STR(?target), "L2%20APS%20Requirements%20Document"))
    )
    OPTIONAL { ?source vocab:NamedElement_name ?sourceName . }
    OPTIONAL { ?target vocab:NamedElement_name ?targetName . }
  }
  UNION
  {
    ?rel rdf:type ?relType .
    ?rel vocab:Relationship_relatedElement ?source .
    ?rel vocab:Relationship_relatedElement ?target .
    FILTER(?source != ?target)
    FILTER(
      CONTAINS(STR(?source), "L2%20APS%20Requirements%20Document") &&
      CONTAINS(STR(?target), "APS%20Requirements%20Flowdown")
    )
    OPTIONAL { ?source vocab:NamedElement_name ?sourceName . }
    OPTIONAL { ?target vocab:NamedElement_name ?targetName . }
  }
}
LIMIT 25

